import pygame
import random

# Define colors
COLORS = {
    "red": (255, 0, 0),
    "green": (0, 255, 0),
    "blue": (0, 0, 255),
    "yellow": (255, 255, 0),
    "cyan": (0, 255, 255),
    "magenta": (255, 0, 255),
    "orange": (255, 165, 0),
    "gray": (128, 128, 128)
}

# Tetromino definitions
TETROMINOS = {
    "I": {"shape": [[1,1,1,1]],             "color": "cyan"},
    "J": {"shape": [[1,0,0],[1,1,1]],       "color": "blue"},
    "L": {"shape": [[0,0,1],[1,1,1]],       "color": "orange"},
    "O": {"shape": [[1,1],[1,1]],           "color": "yellow"},
    "S": {"shape": [[0,1,1],[1,1,0]],       "color": "green"},
    "T": {"shape": [[0,1,0],[1,1,1]],       "color": "magenta"},
    "Z": {"shape": [[1,1,0],[0,1,1]],       "color": "red"}
}

GRID_WIDTH  = 10
GRID_HEIGHT = 20

class Gem:
    """A single colored gem in the grid."""
    def __init__(self, color_name):
        self.color_name = color_name
        self.rgb = COLORS[color_name]

class Tetromino:
    def __init__(self, shape, color_name, x=3, y=0):
        self.shape = [row[:] for row in shape]
        self.color = color_name
        self.x = x
        self.y = y

    def _rotate_shape(self):
        return [list(row) for row in zip(*self.shape[::-1])]

    def rotate(self, grid):
        """Attempt to rotate; revert if invalid."""
        old_shape = self.shape
        self.shape = self._rotate_shape()
        if not is_valid_position(self, grid):
            self.shape = old_shape

    def move(self, dx, grid):
        """Attempt horizontal move; revert if invalid."""
        old_x = self.x
        self.x += dx
        if not is_valid_position(self, grid):
            self.x = old_x

    def soft_drop(self, grid):
        """Move down one; return False if it would collide."""
        old_y = self.y
        self.y += 1
        if not is_valid_position(self, grid):
            self.y = old_y
            return False
        return True

    def hard_drop(self, grid):
        """Drop until collision; lock in place at the end."""
        while self.soft_drop(grid):
            pass
        return False  # indicates it landed

def create_grid(width, height):
    """Initialize empty grid of specified size."""
    return [[None for _ in range(width)] for _ in range(height)]

def is_valid_position(tetromino, grid):
    """Check if tetromino is within bounds and not colliding."""
    for dy, row in enumerate(tetromino.shape):
        for dx, cell in enumerate(row):
            if cell:
                x = tetromino.x + dx
                y = tetromino.y + dy
                if x < 0 or x >= GRID_WIDTH or y < 0 or y >= GRID_HEIGHT:
                    return False
                if grid[y][x] is not None:
                    return False
    return True

def lock_tetromino(tetromino, grid):
    """Convert all occupied cells of the tetromino into Gems in the grid."""
    for dy, row in enumerate(tetromino.shape):
        for dx, cell in enumerate(row):
            if cell:
                x = tetromino.x + dx
                y = tetromino.y + dy
                if 0 <= x < GRID_WIDTH and 0 <= y < GRID_HEIGHT:
                    grid[y][x] = Gem(tetromino.color)

class TetrominoManager:
    """Manages active tetromino, spawning, and locking."""
    def __init__(self, grid):
        self.grid = grid
        self.current = self._spawn_new()

    def _spawn_new(self):
        key = random.choice(list(TETROMINOS.keys()))
        data = TETROMINOS[key]
        # center initial x so shape appears roughly in middle
        start_x = (GRID_WIDTH - len(data["shape"][0])) // 2
        return Tetromino(data["shape"], data["color"], x=start_x, y=0)

    def update(self, command=None):
        """
        command: one of 'left','right','rotate','soft_drop','hard_drop'
        Returns True if piece locked (and a new spawn occurred).
        """
        if command == 'left':
            self.current.move(-1, self.grid)
        elif command == 'right':
            self.current.move(1, self.grid)
        elif command == 'rotate':
            self.current.rotate(self.grid)
        elif command == 'soft_drop':
            landed = not self.current.soft_drop(self.grid)
            if landed:
                lock_tetromino(self.current, self.grid)
                self.current = self._spawn_new()
                return True
        elif command == 'hard_drop':
            self.current.hard_drop(self.grid)
            lock_tetromino(self.current, self.grid)
            self.current = self._spawn_new()
            return True
        else:
            # gravity tick
            landed = not self.current.soft_drop(self.grid)
            if landed:
                lock_tetromino(self.current, self.grid)
                self.current = self._spawn_new()
                return True
        return False

def check_line_clears(grid):
    """Check for and clear full horizontal lines."""
    lines_to_clear = []
    for i, row in enumerate(grid):
        if all(row):  # all cells are gems
            lines_to_clear.append(i)

    for row_index in lines_to_clear:
        del grid[row_index]
        grid.insert(0, [None] * GRID_WIDTH)  # Add empty row at top
    return len(lines_to_clear)  # Return number of lines cleared

def check_match_3(grid):
    """Check for and clear Bejeweled-style match-3."""
    matches = []

    # Horizontal matches
    for y in range(GRID_HEIGHT):
        for x in range(GRID_WIDTH - 2):
            if (grid[y][x] is not None and
                grid[y][x] == grid[y][x+1] and
                grid[y][x] == grid[y][x+2]):
                matches.append(((x, y), (x+1, y), (x+2, y)))

    # Vertical matches
    for x in range(GRID_WIDTH):
        for y in range(GRID_HEIGHT - 2):
            if (grid[y][x] is not None and
                grid[y][x] == grid[y+1][x] and
                grid[y][x] == grid[y+2][x]):
                matches.append(((x, y), (x, y+1), (x, y+2)))

    # Remove duplicates and clear matches
    cleared_positions = set()
    for match in matches:
        for x, y in match:
            cleared_positions.add((x, y))

    # Convert to list for easier manipulation
    cleared_positions = list(cleared_positions)

    # Clear the matched gems from the grid
    for x, y in cleared_positions:
        grid[y][x] = None

    # Apply gravity to move gems down
    for x in range(GRID_WIDTH):
        # Move empty spaces to the top
        empty_count = 0
        for y in range(GRID_HEIGHT):
            if grid[y][x] is None:
                empty_count += 1
            elif empty_count > 0:
                grid[y - empty_count][x] = grid[y][x]
                grid[y][x] = None

    return len(cleared_positions)

def calculate_score(lines_cleared, gems_cleared, chain_reaction_level):
    """Calculate score based on lines cleared and gems cleared."""
    line_clear_score = lines_cleared * (100 * lines_cleared)  # Tetris scoring
    gem_clear_score  = gems_cleared * 50  # Bejeweled scoring
    chain_bonus      = chain_reaction_level * 25 # Bonus for chain reactions

    return line_clear_score + gem_clear_score + chain_bonus
